olor:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.wms-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.wms-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.wms-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.wms-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.wms-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .wms-cta-title{font-size:28px;margin-bottom:16px}\n  .wms-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .wms-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .wms-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.wms-cta-btn{transition:none !important}.wms-cta-btn::before{display:none}}\n\n.et_pb_section:has(.wms-related-section){background:#F5F7FA;padding:0}\n.wms-related-section{padding:60px 5%;background:#F5F7FA;max-width:100%;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto}\n.wms-related-heading{font-family:\'Noto Sans\',sans-serif;font-size:28px;font-weight:600;color:#000864;margin:0 0 32px 0;padding:0;text-align:center;line-height:1.6;-webkit-font-smoothing:auto}\n.wms-related-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:24px;max-width:1200px;margin:0 auto}\n.wms-related-card{display:block;padding:24px;background:#fff;border-radius:12px;text-decoration:none;border:1px solid #e5e7eb;transition:box-shadow 0.3s ease;color:#333;line-height:1.6}\n.wms-related-card:hover{box-shadow:0 8px 24px rgba(0,8,100,0.1)}\n.wms-related-card-title{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 8px 0;padding:0;line-height:1.6;-webkit-font-smoothing:auto}\n.wms-related-card-desc{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#666;margin:0;padding:0;line-height:1.5;-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){.wms-related-card{transition:none}}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="wms-hero">\n    <div class="dw-d-bg dw-d-bg--top dw-d-parallax" style="opacity: 0.12;"></div>\n            <div class="wms-hero-inner">\n                <div class="wms-hero-grid">\n                    <div class="wms-hero-content">\n                        <div class="wms-hero-badge">Warehouse Management System</div>\n                        <h1>Every Item. Every Location. Every Time.</h1>\n                        <p class="wms-hero-subtitle">Smart warehouse management that eliminates searching, reduces errors, and keeps inventory accurate—without endless manual counts.</p>\n                        <div class="wms-hero-ctas">\n                            <a href="../demo/" class="btn-white">Let\'s Talk</a>\n                            <a href="#capabilities" class="btn-outline-white">Explore sFLS</a>\n                        </div>\n                        <div class="wms-hero-stats">\n                            <div class="wms-hero-stat">\n                                <div class="wms-hero-stat-number dw-years">44</div>\n                                <div class="wms-hero-stat-label">Years in Mfg</div>\n                            </div>\n                            <div class="wms-hero-stat">\n                                <div class="wms-hero-stat-number">50K+</div>\n                                <div class="wms-hero-stat-label">Factories</div>\n                            </div>\n                            <div class="wms-hero-stat">\n                                <div class="wms-hero-stat-number">100+</div>\n                                <div class="wms-hero-stat-label">Thai Sites</div>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="wms-hero-visual">\n                        <div class="wms-mockup">\n                            <div class="wms-mockup-grid">\n                                <div class="wms-mockup-cell occupied">A1</div>\n                                <div class="wms-mockup-cell occupied">A2</div>\n                                <div class="wms-mockup-cell">A3</div>\n                                <div class="wms-mockup-cell occupied">A4</div>\n                                <div class="wms-mockup-cell active">A5</div>\n                                <div class="wms-mockup-cell occupied">B1</div>\n                                <div class="wms-mockup-cell">B2</div>\n                                <div class="wms-mockup-cell occupied">B3</div>\n                                <div class="wms-mockup-cell occupied">B4</div>\n                                <div class="wms-mockup-cell">B5</div>\n                                <div class="wms-mockup-cell">C1</div>\n                                <div class="wms-mockup-cell occupied">C2</div>\n                                <div class="wms-mockup-cell occupied">C3</div>\n                                <div class="wms-mockup-cell">C4</div>\n                                <div class="wms-mockup-cell occupied">C5</div>\n                            </div>\n                            <div class="wms-mockup-stats">\n                                <div class="wms-mockup-stat">\n                                    <div class="wms-mockup-stat-value green">99.2%</div>\n                                    <div class="wms-mockup-stat-label">Accuracy</div>\n                                </div>\n                                <div class="wms-mockup-stat">\n                                    <div class="wms-mockup-stat-value">847</div>\n                                    <div class="wms-mockup-stat-label">Locations</div>\n                                </div>\n                                <div class="wms-mockup-stat">\n                                    <div class="wms-mockup-stat-value">73%</div>\n                                    <div class="wms-mockup-stat-label">Utilized</div>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dw-section" style="padding: 40px 0 0; text-align: center;">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n        <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 22px; font-weight: 700; color: #000864; margin: 0 0 12px 0;">What is WMS (Warehouse Management System)?</h2>\n        <p style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; line-height: 1.7; color: #333; margin: 0 0 24px 0;">\n          A Warehouse Management System (WMS) is software that manages warehouse operations including receiving, storage, picking, packing, and shipping. With barcode and RFID tracking, a WMS provides real-time inventory accuracy — so you always know exactly what you have and where it is.\n        </p>\n        <p style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; line-height: 1.7; color: #333;">\n          <strong>DigiWin WMS</strong>, powered by the <strong>sFLS</strong> platform, brings smart inventory management to manufacturing warehouses in Thailand. It replaces manual stock checks and paper-based tracking with barcode/RFID scanning, automated FIFO/FEFO enforcement, location intelligence, and wave picking optimization — covering inbound, production, and outbound warehouse operations end to end.\n        </p>\n      </div>    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Problems"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Problems: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Problems: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="problems-section">\n    <div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <line x1="200" y1="150" x2="200" y2="750" stroke="#000864" stroke-width="2" opacity="0.12"/>\n                    <line x1="400" y1="150" x2="400" y2="750" stroke="#000864" stroke-width="2" opacity="0.12"/>\n                    <line x1="150" y1="250" x2="450" y2="250" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n                    <line x1="150" y1="400" x2="450" y2="400" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n                    <line x1="150" y1="550" x2="450" y2="550" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n                    <rect x="220" y="200" width="30" height="45" rx="2" fill="#000864" opacity="0.12"/>\n                    <rect x="260" y="210" width="30" height="35" rx="2" stroke="#000864" stroke-width="1" fill="none" stroke-dasharray="3 2" opacity="0.15"/>\n                    <rect x="220" y="350" width="30" height="45" rx="2" stroke="#000864" stroke-width="1" fill="none" stroke-dasharray="3 2" opacity="0.15"/>\n                    <rect x="260" y="355" width="30" height="40" rx="2" fill="#000864" opacity="0.12"/>\n                    <rect x="310" y="360" width="30" height="35" rx="2" fill="#000864" opacity="0.1"/>\n                    <rect x="220" y="500" width="30" height="45" rx="2" fill="#000864" opacity="0.1"/>\n                    <text x="280" y="670" font-family="\'Noto Sans\',sans-serif" font-size="14" font-weight="700" fill="#000864" opacity="0.08">SYS: 100</text>\n                    <text x="280" y="700" font-family="\'Noto Sans\',sans-serif" font-size="14" font-weight="700" fill="#00AFF0" opacity="0.12">REAL: 47</text>\n                    <text x="420" y="685" font-family="\'Noto Sans\',sans-serif" font-size="28" font-weight="800" fill="#000864" opacity="0.08">&ne;</text>\n                    <rect x="800" y="250" width="60" height="35" rx="3" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <line x1="810" y1="260" x2="815" y2="260" stroke="#000864" stroke-width="4" opacity="0.15"/>\n                    <line x1="820" y1="260" x2="822" y2="260" stroke="#000864" stroke-width="4" opacity="0.15"/>\n                    <line x1="826" y1="260" x2="830" y2="260" stroke="#000864" stroke-width="4" opacity="0.12"/>\n                    <line x1="834" y1="260" x2="836" y2="260" stroke="#000864" stroke-width="4" opacity="0.15"/>\n                    <line x1="840" y1="260" x2="850" y2="260" stroke="#000864" stroke-width="4" opacity="0.12"/>\n                    <text x="1100" y="400" font-family="\'Noto Sans\',sans-serif" font-size="40" font-weight="800" fill="#000864" opacity="0.06">?</text>\n                    <circle cx="700" cy="500" r="3" fill="#000864" opacity="0.1"/>\n                    <circle cx="1000" cy="600" r="4" fill="#00AFF0" opacity="0.08"/>\n                    <circle cx="1250" cy="300" r="3" fill="#000864" opacity="0.08"/>\n                </svg>\n            </div>\n            <div class="problems-inner" style="position: relative; z-index: 2;">\n                <div class="section-header">\n                    <h2 class="section-title">The Warehouse Chaos Problem</h2>\n                    <p class="section-subtitle">Sound familiar? Every station has its own nightmare.</p>\n                </div>\n    \n                <div class="problems-grid">\n                    \n                    <div class="problem-card">\n                        <div class="problem-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="1" y="3" width="15" height="13" rx="2"/><path d="M16 8h4l3 3v5h-7V8z"/><circle cx="5.5" cy="18.5" r="2.5"/><circle cx="18.5" cy="18.5" r="2.5"/></svg>\n                        </div>\n                        <div class="problem-card-station">Purchase &amp; Arrival</div>\n                        <h3 class="problem-title">"It\'s Here But Not in the System"</h3>\n                        <p class="problem-desc">Purchase orders arrive but receiving is manual — paper logs, miscounts, delayed PO matching. Materials sit on the dock while item data hasn\'t updated.</p>\n                    </div>\n                    \n                    <div class="problem-card">\n                        <div class="problem-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M3 3v18h18"/><path d="M18.7 14l-5.1-5.2-2.8 2.7L7 7.7"/></svg>\n                        </div>\n                        <div class="problem-card-station">Inventory</div>\n                        <h3 class="problem-title">"System Says 500, Shelf Says 340"</h3>\n                        <p class="problem-desc">Physical counts vs. system counts are always different. Year-end reconciliation becomes a nightmare that takes the whole team.</p>\n                    </div>\n                    \n                    <div class="problem-card">\n                        <div class="problem-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/><path d="M11 8v6"/></svg>\n                        </div>\n                        <div class="problem-card-station">Picking</div>\n                        <h3 class="problem-title">"Wrong Part — They Look the Same"</h3>\n                        <p class="problem-desc">Picking errors caused by similar specifications. Visual similarity is not a picking system. Costs you customer trust and expensive returns.</p>\n                    </div>\n                    \n                    <div class="problem-card">\n                        <div class="problem-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M9 11l3 3L22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg>\n                        </div>\n                        <div class="problem-card-station">Quality Inspection</div>\n                        <h3 class="problem-title">"Where\'s That QC Report?"</h3>\n                        <p class="problem-desc">Quality checks happen in a black box — no visibility into inspection status or pass rates until it\'s too late. Materials sit in limbo between receiving and storage.</p>\n                    </div>\n                    \n                    <div class="problem-card">\n                        <div class="problem-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><polyline points="3.27 6.96 12 12.01 20.73 6.96"/><line x1="12" y1="22.08" x2="12" y2="12"/></svg>\n                        </div>\n                        <div class="problem-card-station">Packing &amp; Shipping</div>\n                        <h3 class="problem-title">"We Shipped the Wrong One Again"</h3>\n                        <p class="problem-desc">Packing is error-prone without system guidance — wrong items, wrong quantities, missed shipments. Customers get the wrong item, you eat the return cost.</p>\n                    </div>\n                    \n                    <div class="problem-card">\n                        <div class="problem-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n                        </div>\n                        <div class="problem-card-station">Stock Rotation</div>\n                        <h3 class="problem-title">"FIFO? We Try..."</h3>\n                        <p class="problem-desc">First-in-first-out is the rule. Reality: oldest stock hides in the back while new stock gets picked first. Expired inventory discovered too late.</p>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="wms-capabilities-section">\n    <div class="capabilities-inner" style="position: relative; z-index: 2;">\n                <div class="section-header">\n                    <h2 class="section-title">sFLS: Smart Factory Logistics System</h2>\n                    <p class="section-subtitle">Warehouse management designed for manufacturing</p>\n                </div>\n    \n                <div class="capabilities-grid">\n                    <div class="capability-box">\n                        <div class="capability-box-header">\n                            <div class="capability-box-icon">\n                                <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="10" r="3"/><path d="M12 2a8 8 0 0 0-8 8c0 5.4 7 11.5 7.3 11.8a1 1 0 0 0 1.4 0C13 21.5 20 15.4 20 10a8 8 0 0 0-8-8z"/></svg>\n                            </div>\n                            <div class="capability-box-titles">\n                                <h3 class="capability-box-title">Location Intelligence</h3>\n                                <p class="capability-box-tagline">Every item has an address</p>\n                            </div>\n                        </div>\n                        <p class="capability-box-desc">System knows exactly where to put it and where to find it. No more searching. No more guessing.</p>\n                        <ul class="capability-features">\n                            <li><span class="check">&#10003;</span> Zone/aisle/shelf/bin structure</li>\n                            <li><span class="check">&#10003;</span> Suggested putaway locations based on rules</li>\n                            <li><span class="check">&#10003;</span> Directed picking paths for efficiency</li>\n                            <li><span class="check">&#10003;</span> Visual warehouse maps</li>\n                        </ul>\n                    </div>\n    \n                    <div class="capability-box">\n                        <div class="capability-box-header">\n                            <div class="capability-box-icon">\n                                <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="5" y="2" width="14" height="20" rx="2"/><line x1="12" y1="18" x2="12" y2="18"/></svg>\n                            </div>\n                            <div class="capability-box-titles">\n                                <h3 class="capability-box-title">Barcode/RFID Driven</h3>\n                                <p class="capability-box-tagline">Scan-based accuracy</p>\n                            </div>\n                        </div>\n                        <p class="capability-box-desc">Scan-based transactions eliminate data entry errors. Every move is recorded. Real-time accuracy.</p>\n                        <ul class="capability-features">\n                            <li><span class="check">&#10003;</span> Mobile device support (Android/iOS)</li>\n                            <li><span class="check">&#10003;</span> RFID capability for high-volume</li>\n                            <li><span class="check">&#10003;</span> Real-time inventory updates</li>\n                            <li><span class="check">&#10003;</span> Error prevention with scan validation</li>\n                        </ul>\n                    </div>\n    \n                    <div class="capability-box">\n                        <div class="capability-box-header">\n                            <div class="capability-box-icon">\n                                <svg aria-hidden="true" viewBox="0 0 24 24"><polyline points="23 4 23 10 17 10"/><polyline points="1 20 1 14 7 14"/><path d="M3.51 9a9 9 0 0 1 14.85-3.36L23 10M1 14l4.64 4.36A9 9 0 0 0 20.49 15"/></svg>\n                            </div>\n                            <div class="capability-box-titles">\n                                <h3 class="capability-box-title">FIFO/FEFO Automation</h3>\n                                <p class="capability-box-tagline">Automatic stock rotation</p>\n                            </div>\n                        </div>\n                        <p class="capability-box-desc">System enforces first-in-first-out or first-expired-first-out. No more expired stock hiding in the back.</p>\n                        <ul class="capability-features">\n                            <li><span class="check">&#10003;</span> Lot tracking with receiving dates</li>\n                            <li><span class="check">&#10003;</span> Expiry date management</li>\n                            <li><span class="check">&#10003;</span> Automatic pick sequencing</li>\n                            <li><span class="check">&#10003;</span> Expiry alerts and reports</li>\n                        </ul>\n                    </div>\n    \n                    <div class="capability-box">\n                        <div class="capability-box-header">\n                            <div class="capability-box-icon">\n                                <svg aria-hidden="true" viewBox="0 0 24 24"><polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2"/></svg>\n                            </div>\n                            <div class="capability-box-titles">\n                                <h3 class="capability-box-title">Wave Picking</h3>\n                                <p class="capability-box-tagline">Optimized fulfillment</p>\n                            </div>\n                        </div>\n                        <p class="capability-box-desc">Batch similar orders together. Optimize picker routes. Get more shipments out with the same team.</p>\n                        <ul class="capability-features">\n                            <li><span class="check">&#10003;</span> Order batching by criteria</li>\n                            <li><span class="check">&#10003;</span> Route optimization algorithms</li>\n                            <li><span class="check">&#10003;</span> Labor efficiency tracking</li>\n                            <li><span class="check">&#10003;</span> Pick-to-cart and pick-to-pallet</li>\n                        </ul>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Mobile Functions"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Mobile Functions: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Mobile Functions: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="mobile-functions-section">\n    <div class="dw-d-bg dw-d-bg--corner-br dw-d-bg--subtle"></div>\n            <div class="mobile-functions-inner" style="position: relative; z-index: 2;">\n                <div class="section-header">\n                    <h2 class="section-title">40+ Mobile Functions in Your Pocket</h2>\n                    <p class="section-subtitle">Every warehouse operation — from receiving dock to shipping door — runs on a mobile device.</p>\n                </div>\n    \n                <div class="mobile-modules-grid">\n                    \n                    <div class="mobile-module mobile-module--blue">\n                        <div class="mobile-module-header">\n                            <div class="mobile-module-icon mobile-module-icon--blue">\n                                <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="1" y="3" width="15" height="13" rx="2"/><path d="M16 8h4l3 3v5h-7V8z"/><circle cx="5.5" cy="18.5" r="2.5"/><circle cx="18.5" cy="18.5" r="2.5"/></svg>\n                            </div>\n                            <div>\n                                <div class="mobile-module-name">Purchase</div>\n                                <div class="mobile-module-count">6 Functions</div>\n                            </div>\n                        </div>\n                        <ul class="mobile-function-list">\n                            <li>PO Receipt</li>\n                            <li>Supplier Label Scan</li>\n                            <li>QC Entry</li>\n                            <li>Put-Away</li>\n                            <li>Returns Processing</li>\n                            <li>GRN Generation</li>\n                        </ul>\n                    </div>\n    \n                    \n                    <div class="mobile-module mobile-module--green">\n                        <div class="mobile-module-header">\n                            <div class="mobile-module-icon mobile-module-icon--green">\n                                <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>\n                            </div>\n                            <div>\n                                <div class="mobile-module-name">Production</div>\n                                <div class="mobile-module-count">6 Functions</div>\n                            </div>\n                        </div>\n                        <ul class="mobile-function-list">\n                            <li>Material Issue</li>\n                            <li>WIP Transfer</li>\n                            <li>Component Scan</li>\n                            <li>Batch Recording</li>\n                            <li>Scrap Entry</li>\n                            <li>Production Receipt</li>\n                        </ul>\n                    </div>\n    \n                    \n                    <div class="mobile-module mobile-module--amber">\n                        <div class="mobile-module-header">\n                            <div class="mobile-module-icon mobile-module-icon--amber">\n                                <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><polyline points="3.27 6.96 12 12.01 20.73 6.96"/><line x1="12" y1="22.08" x2="12" y2="12"/></svg>\n                            </div>\n                            <div>\n                                <div class="mobile-module-name">Inventory</div>\n                                <div class="mobile-module-count">9 Functions</div>\n                            </div>\n                        </div>\n                        <ul class="mobile-function-list">\n                            <li>Stock Count</li>\n                            <li>Cycle Count</li>\n                            <li>Location Transfer</li>\n                            <li>Lot Adjustment</li>\n                            <li>Shelf Life Check</li>\n                            <li>Min/Max Alert</li>\n                            <li>Label Print</li>\n                            <li>Consolidation</li>\n                            <li>Physical Inventory</li>\n                        </ul>\n                    </div>\n    \n                    \n                    <div class="mobile-module mobile-module--coral">\n                        <div class="mobile-module-header">\n                            <div class="mobile-module-icon mobile-module-icon--coral">\n                                <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M16 4h2a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h2"/><rect x="8" y="2" width="8" height="4" rx="1"/><path d="M9 14l2 2 4-4"/></svg>\n                            </div>\n                            <div>\n                                <div class="mobile-module-name">Sales</div>\n                                <div class="mobile-module-count">7 Functions</div>\n                            </div>\n                        </div>\n                        <ul class="mobile-function-list">\n                            <li>Pick Order</li>\n                            <li>Wave Pick</li>\n                            <li>Pack Verify</li>\n                            <li>Ship Confirm</li>\n                            <li>BOL Generation</li>\n                            <li>Customer Label</li>\n                            <li>Returns Receipt</li>\n                        </ul>\n                    </div>\n                </div>\n    \n                <p class="mobile-functions-footer">40+ functions — every warehouse operation in your pocket.</p>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Process Flow"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Process Flow: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Process Flow: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="process-flow-section">\n    <div class="process-flow-inner" style="position: relative; z-index: 2;">\n                <div class="section-header">\n                    <h2 class="section-title">End-to-End Warehouse Coverage</h2>\n                    <p class="section-subtitle">sFLS manages every material movement — from dock to floor to door.</p>\n                </div>\n    \n                <div class="process-streams">\n                    \n                    <div class="process-stream process-stream--blue">\n                        <div class="process-stream-badge process-stream-badge--blue">Inbound</div>\n                        <div class="process-stream-steps">\n                            <div class="process-stream-step">Purchase</div>\n                            <span class="process-stream-arrow" aria-hidden="true">&rarr;</span>\n                            <div class="process-stream-step">Check &amp; Accept</div>\n                            <span class="process-stream-arrow" aria-hidden="true">&rarr;</span>\n                            <div class="process-stream-step">IQC</div>\n                            <span class="process-stream-arrow" aria-hidden="true">&rarr;</span>\n                            <div class="process-stream-step">Stock In</div>\n                            <span class="process-stream-arrow" aria-hidden="true">&rarr;</span>\n                            <div class="process-stream-step">Shelf Assignment</div>\n                        </div>\n                    </div>\n    \n                    \n                    <div class="process-stream process-stream--green">\n                        <div class="process-stream-badge process-stream-badge--green">Production</div>\n                        <div class="process-stream-steps">\n                            <div class="process-stream-step">Work Order</div>\n                            <span class="process-stream-arrow" aria-hidden="true">&rarr;</span>\n                            <div class="process-stream-step">Requisition</div>\n                            <span class="process-stream-arrow" aria-hidden="true">&rarr;</span>\n                            <div class="process-stream-step">Picking</div>\n                            <span class="process-stream-arrow" aria-hidden="true">&rarr;</span>\n                            <div class="process-stream-step">Reporting</div>\n                            <span class="process-stream-arrow" aria-hidden="true">&rarr;</span>\n                            <div class="process-stream-step">Stock In</div>\n                            <span class="process-stream-arrow" aria-hidden="true">&rarr;</span>\n                            <div class="process-stream-step">Transfer</div>\n                        </div>\n                    </div>\n    \n                    \n                    <div class="process-stream process-stream--amber">\n                        <div class="process-stream-badge process-stream-badge--amber">Outbound</div>\n                        <div class="process-stream-steps">\n                            <div class="process-stream-step">Order Received</div>\n                            <span class="process-stream-arrow" aria-hidden="true">&rarr;</span>\n                            <div class="process-stream-step">Pick</div>\n                            <span class="process-stream-arrow" aria-hidden="true">&rarr;</span>\n                            <div class="process-stream-step">OQC</div>\n                            <span class="process-stream-arrow" aria-hidden="true">&rarr;</span>\n                            <div class="process-stream-step">Stock Out</div>\n                            <span class="process-stream-arrow" aria-hidden="true">&rarr;</span>\n                            <div class="process-stream-step">Delivery</div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Transformation"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Transformation: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Transformation: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="transformation-section">\n    <div class="dw-d-bg dw-d-bg--corner-br dw-d-bg--subtle"></div>\n            <div class="transformation-inner" style="position: relative; z-index: 2;">\n                <div class="section-header">\n                    <h2 class="section-title">What Changes When sFLS Goes Live</h2>\n                    <p class="section-subtitle">Process by process, the transformation is measurable.</p>\n                </div>\n    \n                \n                <table class="transformation-table">\n                    <caption class="sr-only">Before and after comparison of warehouse processes with sFLS implementation</caption>\n                    <thead>\n                        <tr>\n                            <th scope="col">Process</th>\n                            <th scope="col">Before (Manual)</th>\n                            <th scope="col">After (sFLS)</th>\n                            <th scope="col">Impact</th>\n                        </tr>\n                    </thead>\n                    <tbody>\n                        <tr>\n                            <td class="col-process">Purchase Receipt</td>\n                            <td class="col-before">Manually key in each order — over 8 minutes per receipt</td>\n                            <td class="col-after">Scan code &rarr; real-time ERP update &rarr; EKanBan instant push</td>\n                            <td class="col-improvement">7 &rarr; 3 steps</td>\n                        </tr>\n                        <tr>\n                            <td class="col-process">Material Picking</td>\n                            <td class="col-before">Manual selection — wrong parts, high loss rate</td>\n                            <td class="col-after">Auto-generated pick docs by work order — zero errors via scan</td>\n                            <td class="col-improvement">Near-zero errors</td>\n                        </tr>\n                        <tr>\n                            <td class="col-process">Stock In</td>\n                            <td class="col-before">Manual warehousing — over 10 minutes, labor-intensive</td>\n                            <td class="col-after">Directed putaway — significantly reduced operating time</td>\n                            <td class="col-improvement">Major time savings</td>\n                        </tr>\n                        <tr>\n                            <td class="col-process">Stock Out</td>\n                            <td class="col-before">Long shipment prep — affects on-time delivery</td>\n                            <td class="col-after">Optimized picks &rarr; shorter shipment time &rarr; better OTD rate</td>\n                            <td class="col-improvement">Better OTD</td>\n                        </tr>\n                        <tr>\n                            <td class="col-process">Inventory Count</td>\n                            <td class="col-before">Team works overtime, manual ID is error-prone</td>\n                            <td class="col-after">Full count in hours, error rate nearly zero</td>\n                            <td class="col-improvement">5 &rarr; 3 steps</td>\n                        </tr>\n                    </tbody>\n                </table>\n    \n                \n                <div class="step-reduction-grid">\n                    \n                    <div class="step-reduction-card">\n                        <div class="step-reduction-header">\n                            <div class="step-reduction-title">Receiving Process</div>\n                            <div class="step-reduction-numbers">\n                                <span class="step-number step-number--before">7</span>\n                                <span class="step-number-arrow" aria-hidden="true">&rarr;</span>\n                                <span class="step-number step-number--after">3</span>\n                            </div>\n                        </div>\n                        <div class="step-reduction-columns">\n                            <div>\n                                <div class="step-col-label step-col-label--before">Before</div>\n                                <ol class="step-list step-list--before">\n                                    <li>PO check</li>\n                                    <li>Print out</li>\n                                    <li>Unloading area</li>\n                                    <li>Counting</li>\n                                    <li>Recording</li>\n                                    <li>Key-in data</li>\n                                    <li>Create delivery note</li>\n                                </ol>\n                            </div>\n                            <div>\n                                <div class="step-col-label step-col-label--after">After</div>\n                                <ol class="step-list step-list--after">\n                                    <li><span class="check">&#10003;</span> PO check by app</li>\n                                    <li><span class="check">&#10003;</span> Counting</li>\n                                    <li><span class="check">&#10003;</span> Record by app <em>(delivery note auto-created)</em></li>\n                                </ol>\n                            </div>\n                        </div>\n                    </div>\n    \n                    \n                    <div class="step-reduction-card">\n                        <div class="step-reduction-header">\n                            <div class="step-reduction-title">Inventory Process</div>\n                            <div class="step-reduction-numbers">\n                                <span class="step-number step-number--before">5</span>\n                                <span class="step-number-arrow" aria-hidden="true">&rarr;</span>\n                                <span class="step-number step-number--after">3</span>\n                            </div>\n                        </div>\n                        <div class="step-reduction-columns">\n                            <div>\n                                <div class="step-col-label step-col-label--before">Before</div>\n                                <ol class="step-list step-list--before">\n                                    <li>Inventory plan</li>\n                                    <li>Print paper count cards</li>\n                                    <li>Physical count</li>\n                                    <li>Record quantity</li>\n                                    <li>Accounting adjustment</li>\n                                </ol>\n                            </div>\n                            <div>\n                                <div class="step-col-label step-col-label--after">After</div>\n                                <ol class="step-list step-list--after">\n                                    <li><span class="check">&#10003;</span> Inventory plan</li>\n                                    <li><span class="check">&#10003;</span> Intelligent logistics inventory</li>\n                                    <li><span class="check">&#10003;</span> Accounting adjustment</li>\n                                </ol>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n    \n                <p class="transformation-source">Based on DigiWin WMS implementations across manufacturing and distribution operations</p>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Integration"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Integration: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Integration: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="integration-section">\n    <div class="integration-inner" style="position: relative; z-index: 2;">\n                <div class="section-header">\n                    <h2 class="section-title">Connected to Everything</h2>\n                    <p class="section-subtitle">WMS is the inventory truth for your entire operation</p>\n                </div>\n\n                <div class="integration-visual">\n                    <div class="integration-node">\n                        <div class="integration-node-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18"/><path d="M9 21V9"/></svg>\n                        </div>\n                        <div class="integration-node-name">ERP</div>\n                    </div>\n                    <div class="integration-arrow">&harr;</div>\n                    <div class="integration-node">\n                        <div class="integration-node-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="2" y="7" width="20" height="14" rx="2"/><path d="M6 7V5a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v2"/></svg>\n                        </div>\n                        <div class="integration-node-name">MES</div>\n                    </div>\n                    <div class="integration-arrow">&harr;</div>\n                    <div class="integration-node active">\n                        <div class="integration-node-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/></svg>\n                        </div>\n                        <div class="integration-node-name">WMS</div>\n                    </div>\n                    <div class="integration-arrow">&harr;</div>\n                    <div class="integration-node">\n                        <div class="integration-node-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="3"/><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4"/></svg>\n                        </div>\n                        <div class="integration-node-name">AIoT</div>\n                    </div>\n                </div>\n\n                <div class="integration-message">\n                    <p>Material requests from production trigger picks automatically. Receiving updates ERP inventory in real time. Location data feeds production planning. <strong>One source of inventory truth. Zero reconciliation.</strong></p>\n                </div>\n\n                <div class="integration-links">\n                    <a href="/products/erp/" class="integration-link">Explore ERP &rarr;</a>\n                    <a href="/products/mes/" class="integration-link">Explore MES &rarr;</a>\n                    <a href="/products/aiot/" class="integration-link">Explore AIoT &rarr;</a>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 2"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 2: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 2: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="wms-faq">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n            <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 28px; font-weight: 700; color: #000864; margin-bottom: 32px; text-align: center;">Frequently Asked Questions</h2>\n            <div style="display: flex; flex-direction: column; gap: 12px;">\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">What is a Warehouse Management System (WMS)?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">A Warehouse Management System (WMS) is software that controls and optimizes warehouse operations — from receiving and putaway to picking, packing, and shipping. Unlike distribution-focused WMS solutions, DigiWin WMS (sFLS) is designed specifically for manufacturing warehouses, handling raw materials, WIP inventory, and finished goods with production-linked workflows.</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">How is DigiWin WMS different from generic WMS solutions?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin WMS (sFLS) is built for manufacturing, not distribution. It includes production material kitting, shop floor delivery integration, WIP location tracking, and quality hold management — features that generic WMS solutions designed for e-commerce fulfillment simply don\'t offer. It also shares one database with DigiWin ERP and MES, eliminating integration complexity.</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">Can DigiWin WMS work with my existing ERP?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">Yes. DigiWin WMS can operate standalone or integrate with any existing ERP system via standard APIs. It works natively with DigiWin ERP (T100/iGP) through a shared database, but also connects to SAP, Oracle, and other ERP platforms for inventory synchronization and order management.</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">What hardware do I need for DigiWin WMS?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin WMS works with standard Android or iOS mobile devices for barcode scanning, plus optional RFID readers for high-volume environments. You will need barcode label printers for location and item labeling. The system runs on standard server infrastructure or cloud deployment — no specialized hardware beyond mobile scanners is required.</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">How long does WMS implementation take?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">A typical DigiWin WMS implementation takes 2–4 months, depending on warehouse complexity and the number of locations. Basic implementations with core receiving, putaway, and picking can go live in as little as 6 weeks. The phased approach lets you start with high-impact areas and expand coverage over time.</p>\n                </div>\n              </details>\n            </div>\n          </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Ready to End the Warehouse Chaos?"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Ready to End the Warehouse Chaos?: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Ready to End the Warehouse Chaos?: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="wms-cta-section">\n    <div class="wms-cta-super-d" aria-hidden="true"></div>\n    <div class="wms-cta-wave-flow" aria-hidden="true"></div>\n    <div class="wms-cta-container">\n      <h2 class="wms-cta-title">Ready to End the Warehouse Chaos?</h2>\n      <p class="wms-cta-subtitle">Fill out the form and our team will reach out to discuss your specific warehouse challenges.</p>\n      <div class="wms-cta-btn-row">\n        <a href="/demo/" class="wms-cta-btn wms-cta-btn--primary">Get in Touch</a>\n        <a href="/products/" class="wms-cta-btn wms-cta-btn--ghost">View All Products</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Column"}}},"decoration":{}}} -->\n<!-- wp:html --><style>\n.wms-related-grid{display:grid!important;grid-template-columns:repeat(auto-fit,minmax(280px,1fr))!important;gap:24px!important;max-width:1200px!important;margin:0 auto!important}\n.wms-related-card{display:block!important;padding:24px!important;background:#fff!important;border-radius:12px!important;text-decoration:none!important;border:1px solid #e5e7eb!important;color:#333!important;line-height:1.6!important}\n.wms-related-card-title{font-size:18px!important;font-weight:600!important;color:#000864!important;margin:0 0 8px 0!important}\n.wms-related-card-desc{font-size:14px!important;color:#666!important;margin:0!important}\n</style><div class="wms-related-section">\n    <h2 class="wms-related-heading">Explore Related Solutions</h2>\n    <div class="wms-related-grid">\n      <a href="/products/erp/" class="wms-related-card">\n        <h3 class="wms-related-card-title">ERP</h3>\n        <p class="wms-related-card-desc">End-to-end manufacturing ERP built for Thai factories — from BOM to financials to BOI compliance.</p>\n      </a>\n      <a href="/products/mes/" class="wms-related-card">\n        <h3 class="wms-related-card-title">MES</h3>\n        <p class="wms-related-card-desc">Real-time shop floor execution system — OEE tracking, SPC, and paperless work orders.</p>\n      </a>\n      <a href="/products/aiot/" class="wms-related-card">\n        <h3 class="wms-related-card-title">AIoT</h3>\n        <p class="wms-related-card-desc">Connect machines directly to your ERP with IoT sensors, edge computing, and AI-powered analytics.</p>\n      </a>\n      <a href="/industries/automotive/" class="wms-related-card">\n        <h3 class="wms-related-card-title">Automotive</h3>\n        <p class="wms-related-card-desc">ERP and MES solutions purpose-built for automotive parts manufacturers and OEM suppliers.</p>\n      </a>\n      <a href="/industries/electronics/" class="wms-related-card">\n        <h3 class="wms-related-card-title">Electronics</h3>\n        <p class="wms-related-card-desc">Manufacturing software for electronics assembly, SMT lines, and component traceability.</p>\n      </a>\n      <a href="/industries/metal-plastics/" class="wms-related-card">\n        <h3 class="wms-related-card-title">Metal &amp; Plastics</h3>\n        <p class="wms-related-card-desc">Integrated solutions for die casting, injection molding, and metal fabrication shops.</p>\n      </a>\n    </div>\n  </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100563;

