ce {\n            text-align: center;\n            margin-top: 24px;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            color: #5b6b80;\n            letter-spacing: 0.02em;\n            line-height: 1.6;\n            -webkit-font-smoothing: auto;\n        }\n@media (max-width: 1024px) {\n            .problems-grid {\n                grid-template-columns: repeat(2, 1fr);\n            }\n            .capabilities-grid {\n                grid-template-columns: 1fr;\n                max-width: 600px;\n                margin: 0 auto;\n            }\n            .mobile-modules-grid {\n                grid-template-columns: repeat(2, 1fr);\n            }\n            .process-stream {\n                flex-direction: column;\n                align-items: flex-start;\n            }\n            .process-stream-steps {\n                width: 100%;\n            }\n            .transformation-table {\n                display: block;\n                overflow-x: auto;\n            }\n            .step-reduction-grid {\n                grid-template-columns: 1fr;\n                max-width: 500px;\n                margin: 0 auto;\n            }\n            .integration-visual {\n                flex-direction: column;\n            }\n            .integration-arrow {\n                transform: rotate(90deg);\n                padding: 8px 0;\n            }\n        }\n@media (max-width: 640px) {\n            .wms-hero {\n                padding: 120px 0 60px;\n            }\n            .wms-hero h1 {\n                font-size: 32px;\n            }\n            .problems-grid {\n                grid-template-columns: 1fr;\n                max-width: 400px;\n                margin: 0 auto;\n            }\n            .mobile-modules-grid {\n                grid-template-columns: 1fr;\n                max-width: 360px;\n                margin: 0 auto;\n            }\n            .step-reduction-columns {\n                grid-te